import { useLocation } from "react-router-dom";
import AuthorInfo from "../../components/AuthorInfo";
import ContainerRow from "../../components/ContainerRow";
import NavItem from "../../components/NavItem";
import ProfileAboutMe from "./ProfileAboutMe";
import ProfileArticles from "./ProfileArticles";
import ProfileFavArticles from "./ProfileFavArticles";

function Profile() {
  const { state, pathname } = useLocation();

  const renderContent = () => {
    if (pathname.endsWith("/about-me")) {
      return <ProfileAboutMe />;
    } else if (pathname.endsWith("/favorites")) {
      return <ProfileFavArticles />;
    } else {
      return <ProfileArticles />;
    }
  };

  return (
    <div className="profile-page">
      <div className="user-info">
        <ContainerRow>
          <AuthorInfo />
        </ContainerRow>
      </div>

      <ContainerRow>
        <div className="col-xs-12 col-md-10 offset-md-1">
          <div className="articles-toggle">
            <ul className="nav nav-pills outline-active">
              <NavItem text="About Me" url="about-me" state={state} />
              <NavItem text="My Articles" url="" state={state} />
              <NavItem text="Favorited Articles" url="favorites" state={state} />
            </ul>
          </div>
          {renderContent()}
        </div>
      </ContainerRow>
    </div>
  );
}

export default Profile;

import { useLocation } from "react-router-dom";

function ProfileAboutMe() {
  const { state } = useLocation();
  const userBio = state?.bio;

  return (
    <div className="article-preview">
      {userBio && userBio.trim() !== "" ? (
        <p>{userBio}</p>
      ) : (
        <em>该用户暂未填写个人简介</em>
      )}
    </div>
  );
}

export default ProfileAboutMe;
